const { Manifold, label } = api;

// Helper: axis-aligned box from min/max corners
function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// 16-unit cube body, centered at origin
const body = Manifold.cube([16, 16, 16], true);

// Front face features are at y = -8 (front face) with relief protruding to y = -9
// They overlap the body by 0.5 units so boolean union works
const fy = [-9, -7.5]; // front plate depth: protrudes 1 unit, overlaps 0.5

// Helper for front-face plates
function plate(x0, x1, z0, z1) {
  return box([x0, fy[0], z0], [x1, fy[1], z1]);
}

// Corner rivets on the front face — small 2x2 raised squares at corners
// Corners at x = ±5..±7, z = -7..-5 and z = 5..7
const rivetsShape =
  plate(-7, -5, 5, 7) // top-left
  .add(plate(5, 7, 5, 7)) // top-right
  .add(plate(-7, -5, -7, -5)) // bottom-left
  .add(plate(5, 7, -7, -5)); // bottom-right

// Corner rivets on the top face — same pattern on z=8 face (top)
const ty = [7.5, 9]; // top plate extends upward
function topPlate(x0, x1, y0, y1) {
  return box([x0, y0, ty[0]], [x1, y1, ty[1]]);
}
const topRivetsShape =
  topPlate(-7, -5, -7, -5)
  .add(topPlate(5, 7, -7, -5))
  .add(topPlate(-7, -5, 5, 7))
  .add(topPlate(5, 7, 5, 7));

const rivets = rivetsShape.add(topRivetsShape);

// "?" glyph on the front face using raised cuboids
// The ? consists of: a curved top arc (made of blocks), a gap, and a dot
// Building it as pixel-art blocks:
// Arc top: horizontal bar at top
// Arc right: vertical bar going down-right
// Arc bottom: small horizontal bar turning left
// Vertical gap (empty)
// Dot: small square at bottom

// Scale factor: each "pixel" is ~2x2 units
// Center of face: x=0, z=0. Overall glyph ~6 wide, 10 tall

// Top arc of ?  (approx 3 blocks wide, 2 tall at top)
const qTop = plate(-3, 3, 3, 5); // top horizontal bar of arc

// Right side going down
const qRight = plate(1, 3, 1, 4); // right-side vertical

// Bottom of arc curving left
const qCurve = plate(-1, 1, 0, 2); // bottom of arc, center

// Vertical stroke (the stem going down) — omit the gap naturally
const qStem = plate(-1, 1, -3, -1); // short stem below arc (left side)

// Dot at bottom of ?
const qDot = plate(-1, 1, -6, -4);

const question = qTop.add(qRight).add(qCurve).add(qStem).add(qDot);

return label(body, 'body')
  .add(label(rivets, 'rivets'))
  .add(label(question, 'question'));
